  ex3 = 'She likes to swim in the sea rather than a pool.', ex3_ko = '그녀는 수영장보다 바다에서 수영하는 걸 좋아해요.',
  ex4 = 'In summer I like to swim early in the morning.', ex4_ko = '여름에는 이른 아침에 수영하는 걸 좋아해요.',
