  ex3 = 'He can run fast because he trains every day.', ex3_ko = '그는 매일 훈련하기 때문에 빠르게 달릴 수 있어요.',
  ex4 = 'Can you run fast enough to catch the bus?', ex4_ko = '버스를 잡을 만큼 빠르게 달릴 수 있나요?',
  ex5 = 'I can''t run fast, but I enjoy jogging slowly.', ex5_ko = '빠르게 달리진 못하지만 천천히 조깅하는 걸 즐겨요.'
