UPDATE sentences SET
  ex1 = 'Who do you think will win the final?', ex1_ko = '결승전에서 누가 이길 것 같으세요?',
  ex2 = 'Who do you think will win the final based on today''s performance?', ex2_ko = '오늘 경기력을 보면 결승전에서 누가 이길 것 같으세요?',
