UPDATE sentences SET
  ex1 = 'If we had scored first, the result might have been different.', ex1_ko = '우리가 먼저 골을 넣었다면 결과가 달라졌을 수도 있어요.',
  ex2 = 'If we had scored first, the result might have been different and the crowd more excited.', ex2_ko = '우리가 먼저 골을 넣었다면 결과가 달라졌을 수도 있고 관중도 더 흥분했을 거예요.',
  ex3 = 'The coach believes that if we had scored first, the result might have been different.', ex3_ko = '코치는 우리가 먼저 골을 넣었다면 결과가 달라졌을 수도 있다고 생각해요.',
  ex4 = 'If we had scored first, the result might have been different, but we''ll never know.', ex4_ko = '우리가 먼저 골을 넣었다면 결과가 달라졌을 수도 있지만, 알 수 없는 일이에요.',
  ex5 = 'She kept wondering whether, if they had scored first, the result might have been different.', ex5_ko = '그녀는 먼저 골을 넣었다면 결과가 달라졌을지 계속해서 생각했어요.'
