UPDATE sentences SET
  ex1 = 'The team focused on maintaining possession throughout the game.', ex1_ko = '팀은 경기 내내 볼 점유 유지에 집중했어요.',
  ex2 = 'The team focused on maintaining possession throughout the game to reduce the risk of conceding.', ex2_ko = '팀은 실점 위험을 줄이기 위해 경기 내내 볼 점유 유지에 집중했어요.',
  ex3 = 'The coach praised the team for focusing on maintaining possession throughout the game.', ex3_ko = '코치는 경기 내내 볼 점유 유지에 집중한 팀을 칭찬했어요.',
  ex4 = 'Focusing on maintaining possession throughout the game was central to the winning strategy.', ex4_ko = '경기 내내 볼 점유를 유지하는 것에 집중하는 것이 승리 전략의 핵심이었어요.',
