UPDATE sentences SET
  ex1 = 'The referee should have given a penalty in that situation.', ex1_ko = '그 상황에서 심판은 페널티킥을 선언했어야 해요.',
  ex2 = 'Most people agree that the referee should have given a penalty in that situation.', ex2_ko = '대부분의 사람들은 그 상황에서 심판이 페널티킥을 선언했어야 한다는 데 동의해요.',
  ex3 = 'The player argued that the referee should have given a penalty, but the decision stood.', ex3_ko = '선수는 심판이 페널티킥을 선언했어야 한다고 주장했지만 판정은 번복되지 않았어요.',
  ex4 = 'The referee should have given a penalty in that situation rather than a free kick.', ex4_ko = '그 상황에서 심판은 프리킥이 아닌 페널티킥을 선언했어야 해요.',
