UPDATE sentences SET
  ex1 = 'I''ve been working on my stamina for the upcoming tournament.', ex1_ko = '다가오는 토너먼트를 위해 스태미나를 키우고 있어요.',
  ex2 = 'I''ve been working on my stamina for the upcoming tournament by running every morning.', ex2_ko = '다가오는 토너먼트를 위해 매일 아침 달리기를 하며 스태미나를 키우고 있어요.',
  ex3 = 'She''s been working on her stamina for the upcoming tournament with longer training sessions.', ex3_ko = '그녀는 다가오는 토너먼트를 위해 더 긴 훈련 세션으로 스태미나를 키우고 있어요.',
  ex4 = 'I''ve been working on my stamina for the upcoming tournament because I struggled last time.', ex4_ko = '지난번에 힘들었기 때문에 다가오는 토너먼트를 위해 스태미나를 키우고 있어요.',
  ex5 = 'My coach says I''ve been working on my stamina well and I should be ready for the tournament.', ex5_ko = '코치는 제가 스태미나를 잘 키우고 있어서 토너먼트 준비가 됐을 거라고 해요.'
