UPDATE sentences SET
  ex1 = 'Sportsmanship matters more than winning at all costs.', ex1_ko = '스포츠맨십은 어떤 수를 써서라도 이기는 것보다 더 중요해요.',
  ex2 = 'Sportsmanship matters more than winning at all costs, especially in youth sport.', ex2_ko = '스포츠맨십은 특히 유소년 스포츠에서 어떤 수를 써서라도 이기는 것보다 더 중요해요.',
  ex3 = 'She truly believes that sportsmanship matters more than winning at all costs.', ex3_ko = '그녀는 스포츠맨십이 어떤 수를 써서라도 이기는 것보다 더 중요하다고 진심으로 믿어요.',
  ex4 = 'Coaches should teach players that sportsmanship matters more than winning at all costs.', ex4_ko = '코치는 선수들에게 스포츠맨십이 어떤 수를 써서라도 이기는 것보다 더 중요하다는 것을 가르쳐야 해요.',
  ex5 = 'Sportsmanship matters more than winning at all costs, even when it''s a major final.', ex5_ko = '설령 주요 결승전이라 하더라도 스포츠맨십은 어떤 수를 써서라도 이기는 것보다 더 중요해요.'
WHERE id = 's_sports_B1_07';

UPDATE sentences SET
  ex1 = 'Performance analytics has transformed the way teams approach match preparation.', ex1_ko = '경기력 분석학은 팀들이 경기 준비에 접근하는 방식을 변화시켰어요.',
  ex2 = 'Performance analytics has transformed the way teams approach match preparation over the last decade.', ex2_ko = '경기력 분석학은 지난 10년간 팀들이 경기 준비에 접근하는 방식을 변화시켰어요.',
  ex3 = 'She argues that performance analytics has transformed the way teams approach match preparation at every level.', ex3_ko = '그녀는 경기력 분석학이 모든 수준에서 팀들이 경기 준비에 접근하는 방식을 변화시켰다고 주장해요.',
  ex4 = 'Performance analytics has transformed the way teams approach match preparation, but some coaches remain sceptical.', ex4_ko = '경기력 분석학은 팀들이 경기 준비에 접근하는 방식을 변화시켰지만, 여전히 회의적인 코치들도 있어요.',
  ex5 = 'It is difficult to imagine elite football without the role performance analytics now plays in match preparation.', ex5_ko = '경기 준비에서 경기력 분석학이 현재 하는 역할 없이 엘리트 축구를 상상하기는 어려워요.'
WHERE id = 's_sports_B2_01';

UPDATE sentences SET
  ex1 = 'The data suggests that high-pressing tactics significantly increase the chance of winning.', ex1_ko = '데이터에 따르면 고압박 전술은 승리 가능성을 크게 높인다고 해요.',
  ex2 = 'The data suggests that high-pressing tactics significantly increase the chance of winning when applied consistently.', ex2_ko = '데이터에 따르면 고압박 전술을 일관되게 적용하면 승리 가능성을 크게 높인다고 해요.',
  ex3 = 'She cited research showing that the data suggests high-pressing tactics significantly increase the chance of winning.', ex3_ko = '그녀는 데이터에 따르면 고압박 전술이 승리 가능성을 크게 높인다는 것을 보여주는 연구를 인용했어요.',
  ex4 = 'The data suggests that high-pressing tactics significantly increase the chance of winning, provided the squad is fit enough.', ex4_ko = '데이터에 따르면, 선수단이 충분히 체력이 좋다면 고압박 전술이 승리 가능성을 크게 높인다고 해요.',
  ex5 = 'Not everyone agrees, but the data suggests that high-pressing tactics significantly increase the chance of winning long-term.', ex5_ko = '모두가 동의하는 것은 아니지만, 데이터에 따르면 고압박 전술이 장기적으로 승리 가능성을 크게 높인다고 해요.'
WHERE id = 's_sports_B2_02';

UPDATE sentences SET
  ex1 = 'Without proper periodization, athletes risk overtraining and burnout.', ex1_ko = '적절한 주기화 없이는 선수들이 과훈련과 번아웃의 위험에 빠져요.',
  ex2 = 'Without proper periodization, athletes risk overtraining and burnout regardless of their talent.', ex2_ko = '적절한 주기화 없이는 재능에 상관없이 선수들이 과훈련과 번아웃의 위험에 빠져요.',
  ex3 = 'She learned the hard way that without proper periodization, athletes risk overtraining and burnout.', ex3_ko = '그녀는 적절한 주기화 없이는 선수들이 과훈련과 번아웃의 위험에 빠진다는 것을 어렵게 배웠어요.',
  ex4 = 'Without proper periodization, athletes risk overtraining and burnout, which can end careers prematurely.', ex4_ko = '적절한 주기화 없이는 선수들이 과훈련과 번아웃의 위험에 빠지고, 이는 선수 생활을 조기에 끝낼 수 있어요.',
  ex5 = 'Sports scientists emphasise that without proper periodization, athletes risk overtraining and burnout even during successful seasons.', ex5_ko = '스포츠 과학자들은 적절한 주기화 없이는 성공적인 시즌 중에도 선수들이 과훈련과 번아웃의 위험에 빠질 수 있다고 강조해요.'
WHERE id = 's_sports_B2_03';

UPDATE sentences SET
  ex1 = 'Her tactical awareness sets her apart from other players in the league.', ex1_ko = '그녀의 전술적 인식이 리그의 다른 선수들과 그녀를 차별화해요.',
  ex2 = 'Her tactical awareness sets her apart from other players in the league, especially in high-pressure moments.', ex2_ko = '그녀의 전술적 인식은 특히 고압적인 순간에 리그의 다른 선수들과 그녀를 차별화해요.',
  ex3 = 'Scouts noticed early that her tactical awareness would set her apart from other players.', ex3_ko = '스카우터들은 그녀의 전술적 인식이 다른 선수들과 그녀를 차별화할 것임을 일찍 알아챘어요.',
  ex4 = 'Her tactical awareness sets her apart from other players in the league, and coaches appreciate her vision.', ex4_ko = '그녀의 전술적 인식이 리그의 다른 선수들과 그녀를 차별화하며, 코치들은 그녀의 시야를 높이 평가해요.',
  ex5 = 'It is her tactical awareness more than her physical ability that sets her apart from other players in the league.', ex5_ko = '그녀를 리그의 다른 선수들과 차별화하는 것은 신체적 능력보다 전술적 인식이에요.'
WHERE id = 's_sports_B2_04';

UPDATE sentences SET
  ex1 = 'The coaching staff is reviewing biomechanics footage to correct his running form.', ex1_ko = '코칭 스태프가 그의 달리기 폼을 교정하기 위해 생체역학 영상을 검토하고 있어요.',
  ex2 = 'The coaching staff is reviewing biomechanics footage to correct his running form after his recent injury.', ex2_ko = '코칭 스태프가 최근 부상 이후 그의 달리기 폼을 교정하기 위해 생체역학 영상을 검토하고 있어요.',
  ex3 = 'She was told the coaching staff is reviewing biomechanics footage to correct her running form before the season begins.', ex3_ko = '그녀는 시즌 시작 전에 코칭 스태프가 달리기 폼을 교정하기 위해 생체역학 영상을 검토하고 있다고 들었어요.',
  ex4 = 'The coaching staff is reviewing biomechanics footage to correct his running form, which has been causing knee pain.', ex4_ko = '코칭 스태프가 무릎 통증을 유발하고 있는 그의 달리기 폼을 교정하기 위해 생체역학 영상을 검토하고 있어요.',
  ex5 = 'By reviewing biomechanics footage carefully, the coaching staff aims to correct his running form and reduce injury risk.', ex5_ko = '코칭 스태프는 생체역학 영상을 면밀히 검토함으로써 그의 달리기 폼을 교정하고 부상 위험을 줄이는 것을 목표로 해요.'
WHERE id = 's_sports_B2_05';

UPDATE sentences SET
  ex1 = 'Despite the injury setback, she managed to qualify for the finals.', ex1_ko = '부상이라는 좌절에도 불구하고 그녀는 결승전 진출에 성공했어요.',
  ex2 = 'Despite the injury setback, she managed to qualify for the finals with a stunning performance.', ex2_ko = '부상이라는 좌절에도 불구하고 그녀는 놀라운 경기력으로 결승전 진출에 성공했어요.',
  ex3 = 'Everyone was amazed that despite the injury setback, she managed to qualify for the finals.', ex3_ko = '부상이라는 좌절에도 불구하고 그녀가 결승전 진출에 성공한 것에 모두가 놀랐어요.',
  ex4 = 'Despite the injury setback, she managed to qualify for the finals by pushing through intense rehabilitation.', ex4_ko = '부상이라는 좌절에도 불구하고 그녀는 강도 높은 재활 과정을 이겨내며 결승전 진출에 성공했어요.',
  ex5 = 'The fact that despite the injury setback she managed to qualify for the finals inspired many aspiring athletes.', ex5_ko = '부상이라는 좌절에도 불구하고 결승전 진출에 성공한 사실이 많은 꿈나무 선수들에게 영감을 줬어요.'
WHERE id = 's_sports_B2_06';

UPDATE sentences SET
  ex1 = 'It''s not just about talent — mental resilience is what separates elite athletes.', ex1_ko = '재능만이 전부가 아니에요. 엘리트 선수들을 구분 짓는 것은 정신적 회복력이에요.',
  ex2 = 'It''s not just about talent — mental resilience is what separates elite athletes from the rest of the field.', ex2_ko = '재능만이 전부가 아니에요. 정신적 회복력이 엘리트 선수들과 나머지 선수들을 구분 짓는 거예요.',
  ex3 = 'She always says it''s not just about talent — mental resilience is what separates elite athletes in the long run.', ex3_ko = '그녀는 항상 재능만이 전부가 아니라, 장기적으로는 정신적 회복력이 엘리트 선수들을 구분 짓는다고 말해요.',
  ex4 = 'Many coaches agree: it''s not just about talent — mental resilience is what separates elite athletes under pressure.', ex4_ko = '많은 코치들이 동의해요. 재능만이 전부가 아니라, 압박 상황에서 엘리트 선수들을 구분 짓는 것은 정신적 회복력이에요.',
  ex5 = 'The research is clear: it''s not just about talent — mental resilience is what separates elite athletes at the highest level.', ex5_ko = '연구는 명확해요. 재능만이 전부가 아니에요. 최고 수준에서 엘리트 선수들을 구분 짓는 것은 정신적 회복력이에요.'
WHERE id = 's_sports_B2_07';

UPDATE sentences SET
  ex1 = 'Training at the lactate threshold elicits significant aerobic adaptations over time.', ex1_ko = '젖산 역치에서 훈련하면 시간이 지남에 따라 상당한 유산소 적응이 일어나요.',
  ex2 = 'Training at the lactate threshold elicits significant aerobic adaptations over time, especially in endurance athletes.', ex2_ko = '젖산 역치에서 훈련하면 특히 지구력 선수들에게 시간이 지남에 따라 상당한 유산소 적응이 일어나요.',
  ex3 = 'Research confirms that training at the lactate threshold elicits significant aerobic adaptations over a sixteen-week period.', ex3_ko = '연구에 따르면 젖산 역치에서 훈련하면 16주에 걸쳐 상당한 유산소 적응이 일어난다고 확인됐어요.',
  ex4 = 'Training at the lactate threshold elicits significant aerobic adaptations over time, provided recovery is adequately managed.', ex4_ko = '회복이 적절히 관리된다면, 젖산 역치에서 훈련하면 시간이 지남에 따라 상당한 유산소 적응이 일어나요.',
  ex5 = 'Her coach explained that training at the lactate threshold elicits significant aerobic adaptations and delays fatigue onset.', ex5_ko = '코치는 젖산 역치에서 훈련하면 상당한 유산소 적응이 일어나고 피로 시작을 지연시킨다고 설명했어요.'
WHERE id = 's_sports_C1_01';

UPDATE sentences SET
  ex1 = 'Proprioceptive deficits are commonly observed following ankle sprains in athletes.', ex1_ko = '운동선수들의 발목 염좌 후에는 고유수용성 결핍이 흔히 관찰돼요.',
  ex2 = 'Proprioceptive deficits are commonly observed following ankle sprains in athletes and must be addressed in rehabilitation.', ex2_ko = '운동선수들의 발목 염좌 후에는 고유수용성 결핍이 흔히 관찰되며, 재활 과정에서 반드시 해결해야 해요.',
  ex3 = 'Her physiotherapist explained that proprioceptive deficits are commonly observed following ankle sprains and require targeted training.', ex3_ko = '물리치료사는 발목 염좌 후에는 고유수용성 결핍이 흔히 관찰되며 목표한 훈련이 필요하다고 설명했어요.',
  ex4 = 'Proprioceptive deficits are commonly observed following ankle sprains, which is why balance work is central to rehabilitation.', ex4_ko = '발목 염좌 후에는 고유수용성 결핍이 흔히 관찰되는데, 그것이 바로 재활에서 균형 훈련이 중심이 되는 이유예요.',
  ex5 = 'The study found that proprioceptive deficits are commonly observed following ankle sprains and can persist for several months.', ex5_ko = '연구에 따르면 발목 염좌 후에는 고유수용성 결핍이 흔히 관찰되고 몇 달간 지속될 수 있다고 해요.'
WHERE id = 's_sports_C1_02';

UPDATE sentences SET
  ex1 = 'Sport psychology interventions can help athletes reframe failure as a learning opportunity.', ex1_ko = '스포츠 심리학적 개입은 선수들이 실패를 배움의 기회로 재정의하는 데 도움이 될 수 있어요.',
  ex2 = 'Sport psychology interventions can help athletes reframe failure as a learning opportunity rather than a defeat.', ex2_ko = '스포츠 심리학적 개입은 선수들이 실패를 패배가 아닌 배움의 기회로 재정의하는 데 도움이 될 수 있어요.',
  ex3 = 'She worked with a consultant whose sport psychology interventions helped her reframe failure as a learning opportunity.', ex3_ko = '그녀는 스포츠 심리학적 개입을 통해 실패를 배움의 기회로 재정의하도록 도와준 전문가와 함께 작업했어요.',
  ex4 = 'Sport psychology interventions can help athletes reframe failure as a learning opportunity, which builds long-term mental resilience.', ex4_ko = '스포츠 심리학적 개입은 선수들이 실패를 배움의 기회로 재정의하는 데 도움이 될 수 있으며, 이는 장기적인 정신적 회복력을 쌓아요.',
  ex5 = 'Research suggests that sport psychology interventions can help athletes reframe failure as a learning opportunity and improve future performance.', ex5_ko = '연구에 따르면 스포츠 심리학적 개입은 선수들이 실패를 배움의 기회로 재정의하고 미래 경기력을 향상시키는 데 도움이 될 수 있다고 해요.'
WHERE id = 's_sports_C1_03';

UPDATE sentences SET
  ex1 = 'Governance failures within sporting bodies have eroded public trust significantly.', ex1_ko = '스포츠 단체 내의 거버넌스 실패가 공공의 신뢰를 크게 훼손했어요.',
  ex2 = 'Governance failures within sporting bodies have eroded public trust significantly over the past two decades.', ex2_ko = '스포츠 단체 내의 거버넌스 실패가 지난 20년간 공공의 신뢰를 크게 훼손했어요.',
  ex3 = 'She argued that governance failures within sporting bodies have eroded public trust significantly and must be urgently addressed.', ex3_ko = '그녀는 스포츠 단체 내의 거버넌스 실패가 공공의 신뢰를 크게 훼손했으며 시급히 해결해야 한다고 주장했어요.',
  ex4 = 'Governance failures within sporting bodies have eroded public trust significantly, making reform both urgent and necessary.', ex4_ko = '스포츠 단체 내의 거버넌스 실패가 공공의 신뢰를 크게 훼손해 개혁이 시급하고 필요하게 됐어요.',
  ex5 = 'Multiple reports have documented how governance failures within sporting bodies have eroded public trust significantly at both national and international levels.', ex5_ko = '여러 보고서가 스포츠 단체 내의 거버넌스 실패가 국내외 수준 모두에서 공공의 신뢰를 크게 훼손했다는 것을 기록했어요.'
WHERE id = 's_sports_C1_04';

UPDATE sentences SET
  ex1 = 'Without adequate recovery, neuromuscular fatigue accumulates and performance deteriorates.', ex1_ko = '적절한 회복 없이는 신경근 피로가 누적되고 경기력이 저하돼요.',
  ex2 = 'Without adequate recovery, neuromuscular fatigue accumulates and performance deteriorates rapidly across training sessions.', ex2_ko = '적절한 회복 없이는 훈련 세션 전반에 걸쳐 신경근 피로가 빠르게 누적되고 경기력이 저하돼요.',
  ex3 = 'Her coach warned that without adequate recovery, neuromuscular fatigue accumulates and performance deteriorates significantly.', ex3_ko = '코치는 적절한 회복 없이는 신경근 피로가 누적되고 경기력이 크게 저하된다고 경고했어요.',
  ex4 = 'Without adequate recovery, neuromuscular fatigue accumulates and performance deteriorates, increasing the risk of injury as well.', ex4_ko = '적절한 회복 없이는 신경근 피로가 누적되고 경기력이 저하되며 부상 위험도 높아져요.',
  ex5 = 'The study demonstrated that without adequate recovery, neuromuscular fatigue accumulates and performance deteriorates even in highly trained athletes.', ex5_ko = '연구에 따르면 적절한 회복 없이는 고도로 훈련된 선수들에게서도 신경근 피로가 누적되고 경기력이 저하된다고 나타났어요.'
WHERE id = 's_sports_C1_05';

UPDATE sentences SET
  ex1 = 'Periodization frameworks must account for individual variation in recovery capacity.', ex1_ko = '주기화 프레임워크는 회복 능력의 개인 차이를 반드시 고려해야 해요.',
  ex2 = 'Periodization frameworks must account for individual variation in recovery capacity to be truly effective.', ex2_ko = '진정으로 효과적이려면 주기화 프레임워크는 회복 능력의 개인 차이를 반드시 고려해야 해요.',
  ex3 = 'She emphasised that periodization frameworks must account for individual variation in recovery capacity, not just training load.', ex3_ko = '그녀는 주기화 프레임워크가 훈련 부하만이 아니라 회복 능력의 개인 차이도 반드시 고려해야 한다고 강조했어요.',
  ex4 = 'Periodization frameworks must account for individual variation in recovery capacity, which is often influenced by age and genetics.', ex4_ko = '주기화 프레임워크는 나이와 유전의 영향을 많이 받는 회복 능력의 개인 차이를 반드시 고려해야 해요.',
  ex5 = 'The most sophisticated periodization frameworks must account for individual variation in recovery capacity to optimise long-term athletic development.', ex5_ko = '가장 정교한 주기화 프레임워크는 장기적인 운동 능력 개발을 최적화하기 위해 회복 능력의 개인 차이를 반드시 고려해야 해요.'
WHERE id = 's_sports_C1_06';

UPDATE sentences SET
  ex1 = 'Ethical considerations in elite sport extend well beyond the arena itself.', ex1_ko = '엘리트 스포츠에서의 윤리적 고려는 경기장 자체를 훨씬 넘어서요.',
  ex2 = 'Ethical considerations in elite sport extend well beyond the arena itself to include media, sponsorship, and governance.', ex2_ko = '엘리트 스포츠에서의 윤리적 고려는 경기장 자체를 훨씬 넘어 미디어, 스폰서십, 거버넌스까지 포함해요.',
  ex3 = 'She argued that ethical considerations in elite sport extend well beyond the arena itself and must be taken seriously by all stakeholders.', ex3_ko = '그녀는 엘리트 스포츠에서의 윤리적 고려가 경기장 자체를 훨씬 넘어서며 모든 이해관계자들이 진지하게 받아들여야 한다고 주장했어요.',
  ex4 = 'Ethical considerations in elite sport extend well beyond the arena itself, touching on athlete welfare, representation, and exploitation.', ex4_ko = '엘리트 스포츠에서의 윤리적 고려는 경기장 자체를 훨씬 넘어 선수 복지, 대표성, 착취까지 다뤄요.',
  ex5 = 'The conference concluded that ethical considerations in elite sport extend well beyond the arena itself and must be embedded in institutional culture.', ex5_ko = '회의에서는 엘리트 스포츠에서의 윤리적 고려가 경기장 자체를 훨씬 넘어서며 기관 문화에 내재돼야 한다고 결론지었어요.'
WHERE id = 's_sports_C1_07';

UPDATE sentences SET
  ex1 = 'Tensiomyography provides a non-invasive means of quantifying skeletal muscle contractile properties.', ex1_ko = '텐시오마이오그라피는 골격근의 수축 특성을 정량화하는 비침습적 수단을 제공해요.',
  ex2 = 'Tensiomyography provides a non-invasive means of quantifying skeletal muscle contractile properties without disrupting training schedules.', ex2_ko = '텐시오마이오그라피는 훈련 일정을 방해하지 않고 골격근의 수축 특성을 정량화하는 비침습적 수단을 제공해요.',
  ex3 = 'The sports science team explained that tensiomyography provides a non-invasive means of quantifying skeletal muscle contractile properties in real time.', ex3_ko = '스포츠 과학팀은 텐시오마이오그라피가 실시간으로 골격근의 수축 특성을 정량화하는 비침습적 수단을 제공한다고 설명했어요.',
  ex4 = 'Tensiomyography provides a non-invasive means of quantifying skeletal muscle contractile properties, making it valuable for both research and applied sport settings.', ex4_ko = '텐시오마이오그라피는 골격근의 수축 특성을 정량화하는 비침습적 수단을 제공해, 연구와 응용 스포츠 환경 모두에서 가치 있게 쓰여요.',
  ex5 = 'Because tensiomyography provides a non-invasive means of quantifying skeletal muscle contractile properties, it has been widely adopted in professional sport.', ex5_ko = '텐시오마이오그라피가 골격근의 수축 특성을 정량화하는 비침습적 수단을 제공하기 때문에 프로 스포츠에서 널리 채택됐어요.'
WHERE id = 's_sports_C2_01';

UPDATE sentences SET
  ex1 = 'Chronobiological factors, including circadian rhythm, critically modulate athletic performance across disciplines.', ex1_ko = '일주기 리듬을 포함한 생체시간학적 요소들이 다양한 종목에 걸쳐 운동 경기력을 결정적으로 조절해요.',
  ex2 = 'Chronobiological factors, including circadian rhythm, critically modulate athletic performance across disciplines and must inform training schedules.', ex2_ko = '일주기 리듬을 포함한 생체시간학적 요소들이 다양한 종목에 걸쳐 운동 경기력을 결정적으로 조절하며, 훈련 일정에 반드시 반영돼야 해요.',
  ex3 = 'She cited studies showing that chronobiological factors, including circadian rhythm, critically modulate athletic performance in events held at different times of day.', ex3_ko = '그녀는 일주기 리듬을 포함한 생체시간학적 요소들이 하루 중 다른 시간에 열리는 경기에서 운동 경기력을 결정적으로 조절한다는 연구를 인용했어요.',
  ex4 = 'Chronobiological factors, including circadian rhythm, critically modulate athletic performance across disciplines, which is why competition timing matters enormously.', ex4_ko = '일주기 리듬을 포함한 생체시간학적 요소들이 다양한 종목에 걸쳐 운동 경기력을 결정적으로 조절하기 때문에 대회 시간 선정이 매우 중요해요.',
  ex5 = 'The growing body of evidence confirms that chronobiological factors, including circadian rhythm, critically modulate athletic performance and should guide high-performance scheduling.', ex5_ko = '증가하는 증거들은 일주기 리듬을 포함한 생체시간학적 요소들이 운동 경기력을 결정적으로 조절하며 고성능 일정 수립에 반영돼야 한다는 것을 확인해요.'
WHERE id = 's_sports_C2_02';

UPDATE sentences SET
  ex1 = 'The ergogenic potential of phosphocreatine supplementation remains a subject of ongoing inquiry.', ex1_ko = '인산크레아틴 보충의 에르고제닉 잠재력은 지속적인 연구 주제로 남아 있어요.',
  ex2 = 'The ergogenic potential of phosphocreatine supplementation remains a subject of ongoing inquiry within exercise physiology.', ex2_ko = '인산크레아틴 보충의 에르고제닉 잠재력은 운동 생리학 내에서 지속적인 연구 주제로 남아 있어요.',
  ex3 = 'She noted that the ergogenic potential of phosphocreatine supplementation remains a subject of ongoing inquiry despite decades of research.', ex3_ko = '그녀는 수십 년간의 연구에도 불구하고 인산크레아틴 보충의 에르고제닉 잠재력이 지속적인 연구 주제로 남아 있다고 지적했어요.',
  ex4 = 'The ergogenic potential of phosphocreatine supplementation remains a subject of ongoing inquiry, particularly regarding optimal dosing protocols.', ex4_ko = '인산크레아틴 보충의 에르고제닉 잠재력은 특히 최적의 투여 프로토콜과 관련해 지속적인 연구 주제로 남아 있어요.',
  ex5 = 'While promising, the ergogenic potential of phosphocreatine supplementation remains a subject of ongoing inquiry and should not be overstated.', ex5_ko = '가능성은 있지만 인산크레아틴 보충의 에르고제닉 잠재력은 지속적인 연구 주제로 남아 있으며 과장해서는 안 돼요.'
WHERE id = 's_sports_C2_03';

UPDATE sentences SET
  ex1 = 'Neuromotor adaptations to resistance training are mediated by both central and peripheral mechanisms.', ex1_ko = '저항 훈련에 대한 신경운동 적응은 중추 및 말초 기전 모두에 의해 매개돼요.',
  ex2 = 'Neuromotor adaptations to resistance training are mediated by both central and peripheral mechanisms, which operate simultaneously.', ex2_ko = '저항 훈련에 대한 신경운동 적응은 동시에 작동하는 중추 및 말초 기전 모두에 의해 매개돼요.',
  ex3 = 'The lecture explained that neuromotor adaptations to resistance training are mediated by both central and peripheral mechanisms across all muscle groups.', ex3_ko = '강의에서는 저항 훈련에 대한 신경운동 적응이 모든 근육군에 걸쳐 중추 및 말초 기전 모두에 의해 매개된다고 설명했어요.',
  ex4 = 'Neuromotor adaptations to resistance training are mediated by both central and peripheral mechanisms, explaining why neural gains precede hypertrophy.', ex4_ko = '저항 훈련에 대한 신경운동 적응은 중추 및 말초 기전 모두에 의해 매개되는데, 이것이 신경적 이득이 비대보다 먼저 나타나는 이유를 설명해요.',
  ex5 = 'Understanding that neuromotor adaptations to resistance training are mediated by both central and peripheral mechanisms has reshaped strength and conditioning theory.', ex5_ko = '저항 훈련에 대한 신경운동 적응이 중추 및 말초 기전 모두에 의해 매개된다는 것을 이해하는 것은 근력 및 컨디셔닝 이론을 새롭게 형성했어요.'
WHERE id = 's_sports_C2_04';

UPDATE sentences SET
  ex1 = 'Allometric scaling must be applied when comparing strength outputs across athletes of differing body masses.', ex1_ko = '체중이 다른 선수들의 근력 출력을 비교할 때는 이형성장 척도 조정을 반드시 적용해야 해요.',
  ex2 = 'Allometric scaling must be applied when comparing strength outputs across athletes of differing body masses to ensure fair comparison.', ex2_ko = '공정한 비교를 위해 체중이 다른 선수들의 근력 출력을 비교할 때는 이형성장 척도 조정을 반드시 적용해야 해요.',
  ex3 = 'She argued that allometric scaling must be applied when comparing strength outputs across athletes of differing body masses in research and practice alike.', ex3_ko = '그녀는 연구와 실무 모두에서 체중이 다른 선수들의 근력 출력을 비교할 때는 이형성장 척도 조정을 반드시 적용해야 한다고 주장했어요.',
  ex4 = 'Allometric scaling must be applied when comparing strength outputs across athletes of differing body masses, otherwise results can be misleading.', ex4_ko = '체중이 다른 선수들의 근력 출력을 비교할 때 이형성장 척도 조정을 적용하지 않으면 결과가 잘못 해석될 수 있어요.',
  ex5 = 'The coaching staff confirmed that allometric scaling must be applied when comparing strength outputs across athletes of differing body masses for accurate benchmarking.', ex5_ko = '코칭 스태프는 정확한 벤치마킹을 위해 체중이 다른 선수들의 근력 출력을 비교할 때 이형성장 척도 조정을 반드시 적용해야 한다고 확인했어요.'
WHERE id = 's_sports_C2_05';

UPDATE sentences SET
  ex1 = 'The psychomotor demands of elite competition necessitate a training environment that replicates high-pressure decision-making.', ex1_ko = '엘리트 경쟁의 정신운동적 요구는 고압적인 의사결정을 재현하는 훈련 환경을 필요로 해요.',
  ex2 = 'The psychomotor demands of elite competition necessitate a training environment that replicates high-pressure decision-making under fatigue.', ex2_ko = '엘리트 경쟁의 정신운동적 요구는 피로 상태에서의 고압적인 의사결정을 재현하는 훈련 환경을 필요로 해요.',
  ex3 = 'She explained that the psychomotor demands of elite competition necessitate a training environment that replicates high-pressure decision-making as closely as possible.', ex3_ko = '그녀는 엘리트 경쟁의 정신운동적 요구가 고압적인 의사결정을 가능한 한 실제에 가깝게 재현하는 훈련 환경을 필요로 한다고 설명했어요.',
  ex4 = 'The psychomotor demands of elite competition necessitate a training environment that replicates high-pressure decision-making, which many conventional drills fail to achieve.', ex4_ko = '엘리트 경쟁의 정신운동적 요구는 고압적인 의사결정을 재현하는 훈련 환경을 필요로 하는데, 많은 기존 훈련이 이것을 달성하지 못해요.',
  ex5 = 'Recognising that the psychomotor demands of elite competition necessitate a training environment that replicates high-pressure decision-making has led to new simulation-based coaching methods.', ex5_ko = '엘리트 경쟁의 정신운동적 요구가 고압적인 의사결정을 재현하는 훈련 환경을 필요로 한다는 인식이 새로운 시뮬레이션 기반 코칭 방법으로 이어졌어요.'
WHERE id = 's_sports_C2_06';

UPDATE sentences SET
  ex1 = 'Myofascial dysfunction, if left unaddressed, may perpetuate compensatory movement patterns and predispose athletes to recurrent injury.', ex1_ko = '근막 기능 장애가 해결되지 않으면 보상적 움직임 패턴이 지속되고 선수들이 반복 부상에 취약해질 수 있어요.',
  ex2 = 'Myofascial dysfunction, if left unaddressed, may perpetuate compensatory movement patterns and predispose athletes to recurrent injury throughout their careers.', ex2_ko = '근막 기능 장애가 해결되지 않으면 선수 생활 전반에 걸쳐 보상적 움직임 패턴이 지속되고 반복 부상에 취약해질 수 있어요.',
  ex3 = 'The physiotherapist warned that myofascial dysfunction, if left unaddressed, may perpetuate compensatory movement patterns and predispose athletes to recurrent injury.', ex3_ko = '물리치료사는 근막 기능 장애가 해결되지 않으면 보상적 움직임 패턴이 지속되고 선수들이 반복 부상에 취약해질 수 있다고 경고했어요.',
  ex4 = 'Myofascial dysfunction, if left unaddressed, may perpetuate compensatory movement patterns and predispose athletes to recurrent injury, which is why early intervention is essential.', ex4_ko = '근막 기능 장애가 해결되지 않으면 보상적 움직임 패턴이 지속되고 선수들이 반복 부상에 취약해질 수 있기 때문에 조기 개입이 필수적이에요.',
  ex5 = 'The literature suggests that myofascial dysfunction, if left unaddressed, may perpetuate compensatory movement patterns and predispose athletes to recurrent injury across multiple muscle groups.', ex5_ko = '문헌에 따르면 근막 기능 장애가 해결되지 않으면 여러 근육군에 걸쳐 보상적 움직임 패턴이 지속되고 선수들이 반복 부상에 취약해질 수 있다고 해요.'
WHERE id = 's_sports_C2_07';
